import{_ as t,o as i,c as d,a2 as o}from"./chunks/framework.C90q7Ucc.js";const u=JSON.parse('{"title":"模块边界审计与改进建议","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/module-boundary-audit.md","filePath":"architecture/module-boundary-audit.md","lastUpdated":1780840347000}'),r={name:"architecture/module-boundary-audit.md"};function s(a,e,c,l,n,h){return i(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="模块边界审计与改进建议" tabindex="-1">模块边界审计与改进建议 <a class="header-anchor" href="#模块边界审计与改进建议" aria-label="Permalink to &quot;模块边界审计与改进建议&quot;">​</a></h1><p>本文审计当前主工作区的模块化程度，目标是减少多跳查阅、控制文件数量、降低修改半径。建议不追求“每个接口一个文件”，而是让一个文件自然承载一组功能，并对外提供稳定入口。</p><h2 id="审计结论" tabindex="-1">审计结论 <a class="header-anchor" href="#审计结论" aria-label="Permalink to &quot;审计结论&quot;">​</a></h2><p>当前代码同时存在两类问题：</p><ul><li>少数文件承担过多职责，成为高 fan-out 的中心调度点。</li><li>若干目录把同一功能拆成过多小文件，开发者需要在 args、bootstrap、presentation、handler、support 之间频繁跳转。</li></ul><p><code>src</code> 下共有 332 个 TypeScript 文件。生产代码中热点目录如下：</p><table tabindex="0"><thead><tr><th>模块</th><th style="text-align:right;">文件数</th><th style="text-align:right;">80 行以下文件数</th><th style="text-align:right;">总行数</th><th style="text-align:right;">中位行数</th><th>判断</th></tr></thead><tbody><tr><td><code>src/bridge/command</code></td><td style="text-align:right;">39</td><td style="text-align:right;">10</td><td style="text-align:right;">9768</td><td style="text-align:right;">173</td><td>命令功能拆分偏细，存在多跳链路</td></tr><tr><td><code>src/bridge/session</code></td><td style="text-align:right;">27</td><td style="text-align:right;">11</td><td style="text-align:right;">5525</td><td style="text-align:right;">165</td><td>session use case 与展示 helper 粒度偏碎</td></tr><tr><td><code>src/bridge/turn</code></td><td style="text-align:right;">17</td><td style="text-align:right;">3</td><td style="text-align:right;">3578</td><td style="text-align:right;">133</td><td>交互 turn 已形成子域，但 runner 仍偏重</td></tr><tr><td><code>src/bridge/mirror</code></td><td style="text-align:right;">11</td><td style="text-align:right;">2</td><td style="text-align:right;">2964</td><td style="text-align:right;">161</td><td>粒度较合理，适合作为保留样板</td></tr><tr><td><code>src/runtime/codex/session-index</code></td><td style="text-align:right;">13</td><td style="text-align:right;">6</td><td style="text-align:right;">2756</td><td style="text-align:right;">87</td><td>session index 内部 helper 拆得偏散</td></tr><tr><td><code>src/operator-ui</code></td><td style="text-align:right;">16</td><td style="text-align:right;">3</td><td style="text-align:right;">7040</td><td style="text-align:right;">200</td><td><code>shell.ts</code> 和 <code>assets.ts</code> 偏大</td></tr><tr><td><code>src/configuration</code></td><td style="text-align:right;">17</td><td style="text-align:right;">5</td><td style="text-align:right;">3074</td><td style="text-align:right;">147</td><td>重构后边界清晰，文件数可接受</td></tr></tbody></table><p>最大文件和高 fan-out 入口：</p><table tabindex="0"><thead><tr><th>文件</th><th style="text-align:right;">行数 / import 数</th><th>风险</th></tr></thead><tbody><tr><td><code>src/channels/feishu/adapter.ts</code></td><td style="text-align:right;">6612 行</td><td>Feishu API、事件解析、卡片状态、发送、下载等聚在一起，修改半径过大</td></tr><tr><td><code>src/bridge/host/manager.ts</code></td><td style="text-align:right;">3382 行 / 53 imports</td><td>Bridge lifecycle、adapter 管理、dispatch、mirror、startup notice 混在主协调器</td></tr><tr><td><code>src/operator-ui/shell.ts</code></td><td style="text-align:right;">3186 行</td><td>UI shell、DOM 操作、事件绑定和渲染逻辑聚合过重</td></tr><tr><td><code>src/bridge/command/dispatch.ts</code></td><td style="text-align:right;">922 行 / 31 imports</td><td>slash command 分发中心知道太多命令内部细节</td></tr><tr><td><code>src/bridge/session/support.ts</code></td><td style="text-align:right;">521 行 / 18 imports</td><td>runtime 配置读取、展示 fallback、session helper 交叉</td></tr></tbody></table><h2 id="好的边界样板" tabindex="-1">好的边界样板 <a class="header-anchor" href="#好的边界样板" aria-label="Permalink to &quot;好的边界样板&quot;">​</a></h2><h3 id="配置模块" tabindex="-1">配置模块 <a class="header-anchor" href="#配置模块" aria-label="Permalink to &quot;配置模块&quot;">​</a></h3><p><code>src/configuration</code> 是当前较好的样板：一组功能按 <code>schema / fields / sources / merge / service / migrations</code> 聚合，文件数量不算少，但每个文件承担的是一个稳定子职责。业务代码主要通过 <code>ConfigService</code> 进入，不需要知道 TOML I/O、source chain、node-config 合并和 migration 的内部细节。</p><p>保留原则：</p><ul><li><code>service.ts</code> 是统一入口。</li><li><code>sources.ts</code> 承担来源和文件 I/O。</li><li><code>merge.ts</code> 承担合并和 provenance。</li><li><code>schema.ts</code> / <code>fields.ts</code> 承担 shape 与字段注册。</li><li>业务语义不下沉到配置层。</li></ul><h3 id="mirror-模块" tabindex="-1">Mirror 模块 <a class="header-anchor" href="#mirror-模块" aria-label="Permalink to &quot;Mirror 模块&quot;">​</a></h3><p><code>src/bridge/mirror</code> 的粒度基本合适。它按 runtime、turns、delivery-plan、feedback-controller、subscription-registry、suppression 等稳定子功能组织，文件数没有失控，入口和内部 helper 的关系也较自然。</p><p>保留原则：</p><ul><li>不再继续拆出 trivial helper 文件。</li><li>新增 mirror 行为优先落到现有子功能文件。</li><li>只有形成独立生命周期或状态机时才新增文件。</li></ul><h2 id="主要问题" tabindex="-1">主要问题 <a class="header-anchor" href="#主要问题" aria-label="Permalink to &quot;主要问题&quot;">​</a></h2><h3 id="_1-bridge-命令模块拆分过细" tabindex="-1">1. Bridge 命令模块拆分过细 <a class="header-anchor" href="#_1-bridge-命令模块拆分过细" aria-label="Permalink to &quot;1. Bridge 命令模块拆分过细&quot;">​</a></h3><p><code>src/bridge/command</code> 当前有 39 个文件，同一命令常跨越 handler、args、bootstrap、presentation、options、callback 多个文件。例如终端类命令会在 <code>tmux.ts</code>、<code>tmux-args.ts</code>、<code>runtime-bootstrap.ts</code>、<code>runtime-session.ts</code>、<code>presentation.ts</code>、<code>dispatch.ts</code> 间跳转；runtime 配置命令也会穿过 <code>runtime-settings.ts</code>、<code>runtime-settings-options.ts</code>、<code>runtime-settings-bootstrap.ts</code>、<code>provider-settings.ts</code>、<code>global-settings.ts</code>。</p><p>这类拆分降低了单文件复杂度，但增加了认知成本。开发者要修改一个命令时，经常需要先追分发，再追参数解析，再追展示，再追 session/runtime 副作用。</p><p>建议把命令按功能包聚合，而不是按技术层拆分：</p><ul><li><code>runtime-command.ts</code>：<code>/runtime</code>、<code>/provider</code>、<code>/model</code>、<code>/mode</code>、<code>/sandbox</code>、<code>/network</code>、<code>/r</code> 的解析、写入和回显。</li><li><code>terminal-command.ts</code>：<code>/tmux</code>、<code>/pty</code>、<code>/shell</code> 的参数解析、执行和展示。</li><li><code>session-command.ts</code>：<code>/new</code>、<code>/t</code>、<code>/clear</code>、<code>/takeover</code>、session/thread 选择和确认。</li><li><code>diagnostics-command.ts</code>：<code>/status</code>、<code>/doctor</code>、诊断展示。</li><li><code>command-dispatch.ts</code>：只做 alias、conversation barrier、路由和错误兜底，不直接理解每个命令的内部执行细节。</li></ul><p>迁移时优先把 80 行以下的纯转发或单函数文件合并到对应功能包，例如 <code>runtime-settings-options.ts</code>、<code>runtime-settings-bootstrap.ts</code>、<code>pty-args.ts</code>、<code>tmux-args.ts</code>、<code>shell-args.ts</code>、<code>clear-confirmations.ts</code>、<code>takeover-confirmations.ts</code>。不要先抽新接口，先让相关代码落到同一功能文件中，再看是否需要导出小的测试入口。</p><h3 id="_2-session-use-case-分散在过多小文件" tabindex="-1">2. Session use case 分散在过多小文件 <a class="header-anchor" href="#_2-session-use-case-分散在过多小文件" aria-label="Permalink to &quot;2. Session use case 分散在过多小文件&quot;">​</a></h3><p><code>src/bridge/session/command-use-cases</code> 有 12 个文件，其中 <code>types.ts</code>、<code>clear-confirmation.ts</code>、<code>takeover-confirmation.ts</code>、<code>status-guards.ts</code>、<code>local-runtime-list.ts</code> 都很小。线程绑定、切换、目标解析、source 读取、args 解析又分别落在多个文件。</p><p>建议收敛为 3 个功能文件：</p><ul><li><code>session-thread-commands.ts</code>：thread target、source、binding、switch。</li><li><code>session-lifecycle-commands.ts</code>：new、clear、takeover、confirmation、status guard。</li><li><code>session-list-commands.ts</code>：local runtime list 和展示入口。</li></ul><p>这样开发者处理 <code>/t</code> 或 <code>/new</code> 时可以从一个文件读完主要流程，再按需跳到 registry/store，而不是在 use case 目录里来回定位。</p><h3 id="_3-codex-session-index-helper-文件过碎" tabindex="-1">3. Codex session-index helper 文件过碎 <a class="header-anchor" href="#_3-codex-session-index-helper-文件过碎" aria-label="Permalink to &quot;3. Codex session-index helper 文件过碎&quot;">​</a></h3><p><code>src/runtime/codex/session-index</code> 有 13 个文件，6 个文件不超过 80 行。<code>paths.ts</code>、<code>discovery-scanner.ts</code>、<code>workspace-filter.ts</code>、<code>file-readers.ts</code>、<code>archive-store.ts</code>、<code>sqlite-visibility.ts</code> 都是同一个 session index source discovery 的组成部分。</p><p>建议按读路径聚合：</p><ul><li><code>sources.ts</code>：paths、workspace filter、file readers、discovery scanner、archive store、sqlite visibility。</li><li><code>events.ts</code>：jsonl types、history parser、event mirror parser、tool-call events、internal control events。</li><li><code>core.ts</code>：保留 public list/read/reconcile 入口，隐藏 sources/events 细节。</li></ul><p>这样仍保持 3 个有意义的内部边界，同时减少“为了一个路径 helper 跳一个文件”的成本。</p><h3 id="_4-feishu-adapter-过大" tabindex="-1">4. Feishu adapter 过大 <a class="header-anchor" href="#_4-feishu-adapter-过大" aria-label="Permalink to &quot;4. Feishu adapter 过大&quot;">​</a></h3><p><code>src/channels/feishu/adapter.ts</code> 是当前最大的生产文件，超过 6600 行。它的问题不是“需要无限拆分”，而是多个生命周期混在同一个文件：</p><ul><li>Feishu API request 包装和错误处理。</li><li>webhook / message / card callback 入站解析。</li><li>rich card / streaming card 的 desired state 与 shadow state。</li><li>文件下载和附件处理。</li><li>startup reconciliation 辅助行为。</li></ul><p>建议按 Feishu adapter 的自然功能边界拆成少数几个文件：</p><ul><li><code>adapter.ts</code>：只保留 <code>FeishuAdapter</code> 对外生命周期、接口实现和组合装配。</li><li><code>events.ts</code>：Feishu webhook、消息、卡片 callback 解析。</li><li><code>card-runtime.ts</code>：streaming/rich card desired state、shadow state、flush 和 sync plan。</li><li><code>api-client.ts</code>：Feishu API request、错误归一化、timeout、日志。</li><li><code>resources.ts</code>：文件下载、图片、附件资源处理。</li></ul><p>这会增加少量文件，但显著减少单文件修改半径。不要继续把每个 API endpoint 拆成文件；API client 内部用函数分组即可。</p><h3 id="_5-bridge-host-manager-职责过宽" tabindex="-1">5. Bridge host manager 职责过宽 <a class="header-anchor" href="#_5-bridge-host-manager-职责过宽" aria-label="Permalink to &quot;5. Bridge host manager 职责过宽&quot;">​</a></h3><p><code>src/bridge/host/manager.ts</code> 有 3382 行，且 import 数最高。它是 Bridge 的中心协调器，但目前同时了解 adapter lifecycle、startup notice、message dispatch、mirror reconcile、session cleanup、hot update source 等行为。</p><p>建议先做“职责下沉”，不要再横向拆很多 manager helper：</p><ul><li>adapter 启停和同步计划下沉到 <code>channels/adapter-runtime</code> 已有模块。</li><li>startup notice 和 channel chat reconciliation 收口到现有 <code>bridge/startup-notice-target.ts</code> 或新增一个 <code>startup.ts</code>。</li><li>mirror reconcile 调用只通过 <code>bridge/mirror/runtime.ts</code> 的统一接口。</li><li>manager 保留组合装配、依赖注入和顶层生命周期。</li></ul><p>目标不是把 manager 拆成十几个文件，而是让 manager 不再直接理解每个子系统内部细节。</p><h3 id="_6-operator-ui-shell-过大" tabindex="-1">6. Operator UI shell 过大 <a class="header-anchor" href="#_6-operator-ui-shell-过大" aria-label="Permalink to &quot;6. Operator UI shell 过大&quot;">​</a></h3><p><code>src/operator-ui/shell.ts</code> 和 <code>assets.ts</code> 承担了大量 HTML、DOM 查询、事件绑定和 API 调用。由于当前 UI 是非框架式静态 shell，不能简单按组件库方式细拆，但仍可以按页面功能包聚合：</p><ul><li><code>shell.ts</code>：启动、路由、全局事件和页面切换。</li><li><code>session-view.ts</code>：session 列表、详情、表单和操作。</li><li><code>config-view.ts</code>：全局配置、channel 配置和校验展示。</li><li><code>runtime-view.ts</code>：runtime/provider 状态和命令入口。</li><li><code>ui-api.ts</code>：fetch wrapper 和 payload 类型。</li></ul><p>这里的拆分应以页面工作流为单位，不要按每个按钮/表单控件拆文件。</p><h2 id="推荐推进顺序" tabindex="-1">推荐推进顺序 <a class="header-anchor" href="#推荐推进顺序" aria-label="Permalink to &quot;推荐推进顺序&quot;">​</a></h2><h3 id="p0-建立模块化评审规则" tabindex="-1">P0：建立模块化评审规则 <a class="header-anchor" href="#p0-建立模块化评审规则" aria-label="Permalink to &quot;P0：建立模块化评审规则&quot;">​</a></h3><p>新增或维护一份轻量规则，作为 review checklist：</p><ul><li>一个文件优先承载一组功能，而不是一个接口或一个函数。</li><li>80 行以下文件如果只是单函数转发、常量或薄 wrapper，优先合并回所在功能包。</li><li>超过 1000 行文件需要明确内部分区；超过 2000 行文件应评估是否存在多个生命周期。</li><li>分发层只做路由，不理解业务细节。</li><li>service/facade 可以存在，但必须减少调用方认知，而不是制造更多跳转。</li></ul><h3 id="p1-收敛-bridge-命令目录" tabindex="-1">P1：收敛 Bridge 命令目录 <a class="header-anchor" href="#p1-收敛-bridge-命令目录" aria-label="Permalink to &quot;P1：收敛 Bridge 命令目录&quot;">​</a></h3><p>优先处理 <code>src/bridge/command</code>，因为它文件数最高且是开发者常改入口。建议先选一个纵向功能做样板，例如 terminal 命令或 runtime 配置命令。</p><p>成功标准：</p><ul><li>修改 <code>/tmux</code> 或 <code>/provider</code> 不需要跨 5 个以上 command 文件。</li><li><code>dispatch.ts</code> 的 import 数下降。</li><li>小文件数量减少，而不是新增 facade。</li></ul><h3 id="p2-收敛-session-command-use-cases" tabindex="-1">P2：收敛 Session command-use-cases <a class="header-anchor" href="#p2-收敛-session-command-use-cases" aria-label="Permalink to &quot;P2：收敛 Session command-use-cases&quot;">​</a></h3><p>在命令目录有样板后，把 <code>command-use-cases</code> 合并成 thread/lifecycle/list 三组。这个阶段应保持测试不变，主要移动代码和整理导出。</p><p>成功标准：</p><ul><li><code>/t</code> 相关主流程集中在一个功能文件。</li><li>confirmation/status guard 这类小 helper 不再独立成文件。</li></ul><h3 id="p3-整理-codex-session-index" tabindex="-1">P3：整理 Codex session-index <a class="header-anchor" href="#p3-整理-codex-session-index" aria-label="Permalink to &quot;P3：整理 Codex session-index&quot;">​</a></h3><p>把 discovery/source 相关小文件合并为 <code>sources.ts</code>，把 JSONL/event 解析相关逻辑合并为 <code>events.ts</code>。这个阶段适合配合 runtime 文档更新。</p><p>成功标准：</p><ul><li>session-index 目录从 13 个文件降到约 4 到 6 个文件。</li><li><code>core.ts</code> 只面向 public list/read/reconcile，不再散落路径和 reader 细节。</li></ul><h3 id="p4-拆解-feishu-adapter-的生命周期" tabindex="-1">P4：拆解 Feishu adapter 的生命周期 <a class="header-anchor" href="#p4-拆解-feishu-adapter-的生命周期" aria-label="Permalink to &quot;P4：拆解 Feishu adapter 的生命周期&quot;">​</a></h3><p>这是收益大但风险高的阶段，应在命令/session 收敛后做。拆分要少而稳定，优先提取 card runtime 和 API client。</p><p>成功标准：</p><ul><li><code>adapter.ts</code> 降到 2000 行以内。</li><li>card flush/sync plan 的状态和 API 调用集中在 <code>card-runtime.ts</code>。</li><li>入站事件解析集中在 <code>events.ts</code>。</li></ul><h3 id="p5-operator-ui-按页面工作流整理" tabindex="-1">P5：Operator UI 按页面工作流整理 <a class="header-anchor" href="#p5-operator-ui-按页面工作流整理" aria-label="Permalink to &quot;P5：Operator UI 按页面工作流整理&quot;">​</a></h3><p>UI shell 的拆分应最后做，因为它容易引入细碎“组件文件”。按 session/config/runtime 页面工作流拆，而不是按控件拆。</p><p>成功标准：</p><ul><li><code>shell.ts</code> 只负责启动和页面切换。</li><li>每个页面工作流有单一入口。</li><li>API payload 类型和 fetch wrapper 不散在 DOM 操作中。</li></ul><h2 id="不建议做的事" tabindex="-1">不建议做的事 <a class="header-anchor" href="#不建议做的事" aria-label="Permalink to &quot;不建议做的事&quot;">​</a></h2><ul><li>不要为了降低单文件行数，把每个函数、常量、按钮或 callback 拆成文件。</li><li>不要新增只转发一次的 facade；如果调用方仍要继续跳到实现文件，facade 没有降低认知成本。</li><li>不要把业务 fallback 下沉到底层工具模块，配置重构已经证明这会让边界变厚。</li><li>不要一口气重排所有目录。每次选择一个功能包，先建立可验证的重组样板。</li></ul><h2 id="验证建议" tabindex="-1">验证建议 <a class="header-anchor" href="#验证建议" aria-label="Permalink to &quot;验证建议&quot;">​</a></h2><p>模块化整理以移动代码为主，验证应覆盖被整理功能的使用场景：</p><ul><li>命令目录：<code>npm test -- --unit --grep &quot;command|runtime|provider|tmux|pty|shell&quot;</code>，再跑 <code>npm test -- --mock-e2e</code>。</li><li>session use cases：session registry、channel router、command workflow 定向测试。</li><li>session-index：Codex session index、mirror parser、history parser 定向测试。</li><li>Feishu adapter：Feishu adapter unit/e2e、streaming card、rich card 和 doc-as-chat 相关测试。</li><li>UI shell：operator-ui route/application 单测和 <code>npm run docs:build</code>。</li></ul><p>每个阶段完成后更新对应架构文档，尤其是 <a href="./current">当前架构</a>、<a href="./../product/developer-map">开发者源码地图</a> 和本审计文档。</p>',80)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
